using System;
using System.Reflection;
using System.Linq;
using System.Collections.Generic;

var dllPaths = new[]
{
    "/home/runner/.nuget/packages/microsoft.extensions.ai.abstractions/10.3.0/lib/net9.0/Microsoft.Extensions.AI.Abstractions.dll",
    "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.1/lib/net9.0/Microsoft.Extensions.AI.dll",
    "/home/runner/.nuget/packages/microsoft.extensions.ai.openai/10.3.0/lib/net9.0/Microsoft.Extensions.AI.OpenAI.dll",
    "/home/runner/.nuget/packages/microsoft.agents.ai/1.5.0/lib/net9.0/Microsoft.Agents.AI.dll",
    "/home/runner/.nuget/packages/openai/2.10.0/lib/net8.0/OpenAI.dll"
};

foreach (var dllPath in dllPaths)
{
    Console.WriteLine($"\n{'='*80}");
    Console.WriteLine($"ASSEMBLY: {System.IO.Path.GetFileName(dllPath)}");
    Console.WriteLine($"{'='*80}");

    try
    {
        var asm = Assembly.LoadFrom(dllPath);
        var publicTypes = asm.GetTypes()
            .Where(t => t.IsPublic && !t.Name.StartsWith("<"))
            .OrderBy(t => t.Name);

        Console.WriteLine($"\nPublic Types ({publicTypes.Count()}):");

        foreach (var type in publicTypes)
        {
            var typeKind = type.IsInterface ? "interface" : type.IsEnum ? "enum" : "class";
            Console.WriteLine($"\n  [{typeKind}] {type.FullName}");

            // Show key members for interfaces and important classes
            if (type.IsInterface || type.Name.Contains("Chat") || type.Name.Contains("Client") || type.Name.Contains("Function") || type.Name.Contains("Options") || type.Name.Contains("Message"))
            {
                var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
                    .Where(m => !m.IsSpecialName)
                    .Take(10);

                var properties = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static)
                    .Take(8);

                foreach (var prop in properties)
                {
                    var getset = "";
                    if (prop.CanRead) getset += "get;";
                    if (prop.CanWrite) getset += "set;";
                    Console.WriteLine($"      {prop.PropertyType.Name} {prop.Name} {{ {getset} }}");
                }

                foreach (var method in methods)
                {
                    var returnType = method.ReturnType.Name;
                    var paramStr = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                    Console.WriteLine($"      {returnType} {method.Name}({paramStr})");
                }
            }
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"ERROR: {ex.Message}");
    }
}
