using System;
using System.Reflection;
using System.Linq;

var dllPaths = new Dictionary<string, string>()
{
    { "Microsoft.Extensions.AI.Abstractions", "/home/runner/.nuget/packages/microsoft.extensions.ai.abstractions/10.3.0/lib/net9.0/Microsoft.Extensions.AI.Abstractions.dll" },
    { "Microsoft.Extensions.AI", "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.1/lib/net9.0/Microsoft.Extensions.AI.dll" },
    { "Microsoft.Extensions.AI.OpenAI", "/home/runner/.nuget/packages/microsoft.extensions.ai.openai/10.3.0/lib/net9.0/Microsoft.Extensions.AI.OpenAI.dll" },
    { "Microsoft.Agents.AI", "/home/runner/.nuget/packages/microsoft.agents.ai/1.5.0/lib/net9.0/Microsoft.Agents.AI.dll" }
};

foreach (var entry in dllPaths)
{
    Console.WriteLine($"\n{'='*80}\n{entry.Key}\n{'='*80}\n");

    try
    {
        var asm = Assembly.LoadFrom(entry.Value);
        var types = asm.GetTypes()
            .Where(t => t.IsPublic && !t.Name.StartsWith("<"))
            .GroupBy(t => t.Namespace)
            .OrderBy(g => g.Key);

        foreach (var ns in types)
        {
            Console.WriteLine($"\nNamespace: {ns.Key}");
            foreach (var type in ns.OrderBy(t => t.Name))
            {
                var typeKind = type.IsInterface ? "interface" : type.IsEnum ? "enum" : type.IsValueType ? "struct" : "class";
                Console.Write($"  {typeKind} {type.Name}");

                // Show base class/interfaces for important types
                if (type.IsInterface || type.Name.Contains("Chat") || type.Name.Contains("Client") || type.Name.Contains("Function"))
                {
                    var interfaces = type.GetInterfaces().Where(i => !i.Name.StartsWith("I") || i.Name.Length > 1);
                    var baseType = type.BaseType != null && type.BaseType != typeof(object) ? type.BaseType.Name : null;
                    if (baseType != null || interfaces.Any())
                    {
                        Console.Write(" : ");
                        var bases = new System.Collections.Generic.List<string>();
                        if (baseType != null) bases.Add(baseType);
                        bases.AddRange(interfaces.Select(i => i.Name));
                        Console.Write(string.Join(", ", bases));
                    }
                }
                Console.WriteLine();
            }
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error loading: {ex.GetBaseException().Message}");
    }
}
