using System.ComponentModel;
using Microsoft.Extensions.AI;

// --- Tool implementations ---------------------------------------------------

var notebook = new Notebook();

[Description("Search the web for information on a given query. Returns a list of result snippets.")]
static string WebSearch([Description("The search query")] string query)
{
    Console.ForegroundColor = ConsoleColor.DarkCyan;
    Console.WriteLine($"  🔍 Searching the web for: \"{query}\"");
    Console.ResetColor();

    // Simulated web results keyed on common research topics.
    var results = new Dictionary<string, string[]>(StringComparer.OrdinalIgnoreCase)
    {
        ["quantum computing"] =
        [
            "Quantum computing uses qubits that can exist in superposition, enabling parallel computation. " +
            "Google's Willow chip (2024) demonstrated error-corrected qubits at scale.",
            "IBM's 1,121-qubit Condor processor pushes the boundary of quantum hardware. " +
            "Practical applications include cryptography, drug discovery, and optimization problems.",
            "Microsoft's topological qubits aim for inherently stable quantum states, " +
            "potentially reducing error-correction overhead by orders of magnitude."
        ],
        ["artificial intelligence"] =
        [
            "Large language models like GPT-4 and Claude demonstrate emergent reasoning capabilities. " +
            "The field is moving toward multimodal AI that processes text, images, and audio together.",
            "AI agents that use tools and plan multi-step actions are a key 2025 research direction. " +
            "Frameworks like Microsoft.Extensions.AI standardize how .NET apps integrate AI.",
            "Concerns about AI safety include alignment, hallucination, and societal impact. " +
            "Regulatory efforts like the EU AI Act aim to set guardrails for high-risk AI systems."
        ],
        ["climate change"] =
        [
            "Global average temperatures have risen ~1.1°C above pre-industrial levels. " +
            "The Paris Agreement targets limiting warming to 1.5°C, requiring drastic emission cuts.",
            "Renewable energy capacity grew 50% in 2024, led by solar. Battery storage costs " +
            "fell below $100/kWh, making grid-scale storage economically viable.",
            "Carbon capture and direct air capture technologies are scaling up, with projects " +
            "like Climeworks' Mammoth plant capturing 36,000 tons of CO₂ per year."
        ]
    };

    // Try to match the query to one of the known topics.
    var matched = results
        .Where(kv => query.Contains(kv.Key, StringComparison.OrdinalIgnoreCase)
                   || kv.Key.Contains(query, StringComparison.OrdinalIgnoreCase))
        .SelectMany(kv => kv.Value)
        .ToList();

    if (matched.Count > 0)
        return string.Join("\n\n", matched.Select((r, i) => $"[Result {i + 1}] {r}"));

    return $"[Result 1] General information about \"{query}\": This is an active area of research " +
           $"with many recent developments. Key themes include technological advances, societal impact, " +
           $"and policy considerations.\n\n" +
           $"[Result 2] Recent studies on \"{query}\" highlight growing investment and interest from " +
           $"both public and private sectors, with breakthroughs expected in the coming years.";
}

[Description("Save a research note. Use this to record important findings during research.")]
string SaveNote(
    [Description("A short title for the note")] string title,
    [Description("The content of the note")] string content)
{
    notebook.Add(title, content);
    Console.ForegroundColor = ConsoleColor.DarkYellow;
    Console.WriteLine($"  📝 Note saved: \"{title}\"");
    Console.ResetColor();
    return $"Note saved: \"{title}\" ({content.Length} chars)";
}

[Description("Retrieve all saved research notes so far.")]
string GetNotes()
{
    var notes = notebook.GetAll();
    Console.ForegroundColor = ConsoleColor.DarkYellow;
    Console.WriteLine($"  📒 Retrieved {notes.Count} note(s)");
    Console.ResetColor();

    if (notes.Count == 0)
        return "No notes saved yet.";

    return string.Join("\n\n", notes.Select((n, i) =>
        $"--- Note {i + 1}: {n.Title} ---\n{n.Content}"));
}

// --- Agent setup -------------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.ForegroundColor = ConsoleColor.Red;
    Console.WriteLine("Error: Set the OPENAI_API_KEY environment variable to run this agent.");
    Console.ResetColor();
    Console.WriteLine("  export OPENAI_API_KEY=sk-...");
    Console.WriteLine("  Optionally set OPENAI_MODEL (default: gpt-4o-mini)");
    return;
}

var chatClient = new ChatClientBuilder(
        new OpenAI.Chat.ChatClient(model, apiKey).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearch),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetNotes),
};

// --- Interactive loop --------------------------------------------------------

Console.ForegroundColor = ConsoleColor.Green;
Console.WriteLine("╔══════════════════════════════════════════════╗");
Console.WriteLine("║        🔬  Research Agent  (AI-powered)      ║");
Console.WriteLine("╠══════════════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic and the agent will:           ║");
Console.WriteLine("║   • Search the web for information           ║");
Console.WriteLine("║   • Take structured notes on findings        ║");
Console.WriteLine("║   • Produce a summary of its research        ║");
Console.WriteLine("║                                              ║");
Console.WriteLine("║  Type 'quit' to exit.                        ║");
Console.WriteLine("╚══════════════════════════════════════════════╝");
Console.ResetColor();
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic))
        continue;
    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System,
            """
            You are a research agent. When given a topic you MUST:
            1. Use the WebSearch tool to find information (search at least twice with different queries).
            2. Use the SaveNote tool to record each key finding as a separate note.
            3. Use the GetNotes tool to review all your notes.
            4. Finally, write a comprehensive summary of your research with sections and citations to your notes.
            Always use tools — do not rely solely on prior knowledge.
            """),
        new(ChatRole.User, $"Research the following topic and provide a detailed summary: {topic}")
    };

    var options = new ChatOptions { Tools = tools };

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\n  Agent is researching...\n");
    Console.ResetColor();

    try
    {
        var response = await chatClient.GetResponseAsync(messages, options);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("\n═══ Research Summary ═══════════════════════════\n");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"\n  Error: {ex.Message}");
        Console.ResetColor();
    }
}

Console.WriteLine("Goodbye!");

// --- Notebook helper ---------------------------------------------------------

class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    public void Add(string title, string content) => _notes.Add((title, content));
    public List<(string Title, string Content)> GetAll() => [.. _notes];
    public void Clear() => _notes.Clear();
}

